static inline uint32_t CeilDiv(uint32_t a, uint32_t b)
{
    return (a + b - 1u) / b;
}

static ge::graphStatus TilingFunc(gert::TilingContext *context)
{
    ConvTransposed3dAsymmetricInputAsymmetricKernelStridedPaddedGroupedCustomTilingData tiling;

    const gert::Shape *x_shape = context->GetInputShape(0);
    const gert::Shape *w_shape = context->GetInputShape(1);

    const uint32_t n  = static_cast<uint32_t>(x_shape->GetDim(0));
    const uint32_t cI = static_cast<uint32_t>(x_shape->GetDim(1));
    const uint32_t dI = static_cast<uint32_t>(x_shape->GetDim(2));
    const uint32_t hI = static_cast<uint32_t>(x_shape->GetDim(3));
    const uint32_t wI = static_cast<uint32_t>(x_shape->GetDim(4));

    const uint32_t cW0 = static_cast<uint32_t>(w_shape->GetDim(0)); // in_channels
    const uint32_t cW1 = static_cast<uint32_t>(w_shape->GetDim(1)); // out_channels/groups
    const uint32_t kD  = static_cast<uint32_t>(w_shape->GetDim(2));
    const uint32_t kH  = static_cast<uint32_t>(w_shape->GetDim(3));
    const uint32_t kW  = static_cast<uint32_t>(w_shape->GetDim(4));

    const gert::RuntimeAttrs *attrs = context->GetAttrs();

    const int64_t *stride = attrs->GetAttrPointer<int64_t>(0);
    const int64_t *padding = attrs->GetAttrPointer<int64_t>(1);
    const int64_t *outpad = attrs->GetAttrPointer<int64_t>(2);
    const int64_t groups = *attrs->GetAttrPointer<int64_t>(3);
    const int64_t *dilation = attrs->GetAttrPointer<int64_t>(4);

    const uint32_t sD = static_cast<uint32_t>(stride[0]);
    const uint32_t sH = static_cast<uint32_t>(stride[1]);
    const uint32_t sW = static_cast<uint32_t>(stride[2]);

    const uint32_t pD = static_cast<uint32_t>(padding[0]);
    const uint32_t pH = static_cast<uint32_t>(padding[1]);
    const uint32_t pW = static_cast<uint32_t>(padding[2]);

    const uint32_t oD = static_cast<uint32_t>(outpad[0]);
    const uint32_t oH = static_cast<uint32_t>(outpad[1]);
    const uint32_t oW = static_cast<uint32_t>(outpad[2]);

    const uint32_t dD = static_cast<uint32_t>(dilation[0]);
    const uint32_t dH = static_cast<uint32_t>(dilation[1]);
    const uint32_t dW = static_cast<uint32_t>(dilation[2]);

    const uint32_t cO = static_cast<uint32_t>(cW1 * static_cast<uint32_t>(groups));

    // ConvTranspose output formula: out = (in - 1) * stride - 2*pad + dilation*(ker - 1) + output_padding + 1
    const uint32_t dO = (dI - 1U) * sD - 2U * pD + dD * (kD - 1U) + oD + 1U;
    const uint32_t hO = (hI - 1U) * sH - 2U * pH + dH * (kH - 1U) + oH + 1U;
    const uint32_t wO = (wI - 1U) * sW - 2U * pW + dW * (kW - 1U) + oW + 1U;

    // Conservative blockDim
    uint32_t blockDim = std::min<uint32_t>(24U, std::max<uint32_t>(8U, CeilDiv(cO * dO * hO * wO, 32768U)));

    context->SetBlockDim(blockDim);

    tiling.set_n(n);
    tiling.set_cIn(cI);
    tiling.set_dIn(dI);
    tiling.set_hIn(hI);
    tiling.set_wIn(wI);

    tiling.set_cOut(cO);
    tiling.set_kD(kD);
    tiling.set_kH(kH);
    tiling.set_kW(kW);

    tiling.set_dOut(dO);
    tiling.set_hOut(hO);
    tiling.set_wOut(wO);

    tiling.set_strideD(sD);
    tiling.set_strideH(sH);
    tiling.set_strideW(sW);

    tiling.set_padD(pD);
    tiling.set_padH(pH);
    tiling.set_padW(pW);

    tiling.set_outPadD(oD);
    tiling.set_outPadH(oH);
    tiling.set_outPadW(oW);

    tiling.set_dilD(dD);
    tiling.set_dilH(dH);
    tiling.set_dilW(dW);

    tiling.set_groups(static_cast<uint32_t>(groups));
    tiling.set_blockDim(blockDim);

    tiling.SaveToBuffer(context->GetRawTilingData()->GetData(),
                        context->GetRawTilingData()->GetCapacity());
    context->GetRawTilingData()->SetDataSize(tiling.GetDataSize());

    size_t *workspace = context->GetWorkspaceSizes(1);
    workspace[0] = 0;
    return ge::GRAPH_SUCCESS;
}

