    __aicore__ inline void Init(GM_ADDR x, GM_ADDR w, GM_ADDR y,
                                uint32_t n, uint32_t cIn,
                                uint32_t dIn, uint32_t hIn, uint32_t wIn,
                                uint32_t cOut,
                                uint32_t kD, uint32_t kH, uint32_t kW,
                                uint32_t dOut, uint32_t hOut, uint32_t wOut,
                                uint32_t strideD, uint32_t strideH, uint32_t strideW,
                                uint32_t padD, uint32_t padH, uint32_t padW,
                                uint32_t outPadD, uint32_t outPadH, uint32_t outPadW,
                                uint32_t dilD, uint32_t dilH, uint32_t dilW,
                                uint32_t groups)
    {
        n_ = n; cIn_ = cIn; dIn_ = dIn; hIn_ = hIn; wIn_ = wIn;
        cOut_ = cOut;
        kD_ = kD; kH_ = kH; kW_ = kW;
        dOut_ = dOut; hOut_ = hOut; wOut_ = wOut;
        strideD_ = strideD; strideH_ = strideH; strideW_ = strideW;
        padD_ = padD; padH_ = padH; padW_ = padW;
        outPadD_ = outPadD; outPadH_ = outPadH; outPadW_ = outPadW;
        dilD_ = dilD; dilH_ = dilH; dilW_ = dilW;
        groups_ = groups;

        xGm_.SetGlobalBuffer((__gm__ float*)x, n_ * cIn_ * dIn_ * hIn_ * wIn_);
        wGm_.SetGlobalBuffer((__gm__ float*)w, cIn_ * (cOut_ / groups_) * kD_ * kH_ * kW_);
        yGm_.SetGlobalBuffer((__gm__ float*)y, n_ * cOut_ * dOut_ * hOut_ * wOut_);
    }

    __aicore__ inline void Process()
    {
        ConvBackpropApi::Conv3DBackpropInput<float, uint32_t, uint32_t, uint32_t> gradInput_;

        // Set tensors
        gradInput_.SetWeight(wGm_);
        gradInput_.SetGradOutput(xGm_);
        // Set destination as grad input (which is our output)
        gradInput_.SetGradInput(yGm_);

        // Set convolution parameters
        gradInput_.SetStride(strideD_, strideH_, strideW_);
        gradInput_.SetPadding(padD_, padH_, padW_);
        gradInput_.SetOutputPadding(outPadD_, outPadH_, outPadW_);
        gradInput_.SetDilation(dilD_, dilH_, dilW_);
        gradInput_.SetGroups(groups_);

        // Shapes
        gradInput_.SetInputShape(n_, cIn_, dIn_, hIn_, wIn_);
        gradInput_.SetWeightShape(cIn_, (cOut_ / groups_), kD_, kH_, kW_);
        gradInput_.SetOutputShape(n_, cOut_, dOut_, hOut_, wOut_);

        // Execute
        gradInput_.Process();
    }

